import * as THREE from 'three';

/**
 * The pointed-arch silhouette shared by the stone opening and the portal
 * surface. Centred on the origin in the local XY plane, facing +Z.
 *
 * width / height match the inner opening between the pillars, lintel and
 * plinth of a WallBay so the glowing surface sits flush inside the stone.
 */
export function makeArchShape(width = 1.72, height = 6.18): THREE.Shape {
  const shape = new THREE.Shape();

  const halfW = width / 2;
  const halfH = height / 2;
  const springLine = halfH - 1.9;
  const crown = halfH;

  shape.moveTo(-halfW, -halfH);
  shape.lineTo(-halfW, springLine);

  shape.bezierCurveTo(
    -halfW,
    springLine + 0.9,
    -halfW * 0.75,
    crown - 0.15,
    0,
    crown
  );

  shape.bezierCurveTo(
    halfW * 0.75,
    crown - 0.15,
    halfW,
    springLine + 0.9,
    halfW,
    springLine
  );

  shape.lineTo(halfW, -halfH);
  shape.closePath();

  return shape;
}

/**
 * A thin arch-shaped ring (outer arch with an inner arch cut out of it),
 * used for the glowing lip that hugs the stone opening.
 */
export function makeArchRing(
  outerWidth = 1.9,
  outerHeight = 6.4,
  thickness = 0.12
): THREE.Shape {
  const outer = makeArchShape(outerWidth, outerHeight);
  const inner = makeArchShape(outerWidth - thickness * 2, outerHeight - thickness * 2);
  // Reverse the inner path so it reads as a hole.
  outer.holes.push(new THREE.Path(inner.getPoints(128).reverse()));
  return outer;
}

/** Half-extents of the default arch, handy for shader normalisation. */
export const ARCH_HALF_WIDTH = 1.72 / 2;
export const ARCH_HALF_HEIGHT = 6.18 / 2;
